import{_ as t,o as n,c as o,a3 as a}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"83. Union Matters","description":"","frontmatter":{"title":"83. Union Matters","eba":"Allied Health Professionals 2021-2026","topics":["leave","annual-leave","parental-leave","family-violence-leave"]},"headers":[],"relativePath":"ebas/allied-health/union-matters/83-union-matters.md","filePath":"ebas/allied-health/union-matters/83-union-matters.md"}'),i={name:"ebas/allied-health/union-matters/83-union-matters.md"};function r(s,e,l,p,h,c){return n(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="_83-union-matters" tabindex="-1">83. Union Matters <a class="header-anchor" href="#_83-union-matters" aria-label="Permalink to &quot;83. Union Matters&quot;">​</a></h1><p><strong>83.1</strong> Access to Employees – General The Union will have access to Employees for any process arising under this Agreement and an Employee may be represented by the Union for any process under this Agreement (for example, in relation to a request for an extension of a period of unpaid parental leave under subclause 70.14, the consultation on alternative annual leave days under subclause 59.3(e) or in relation to a request for individual support by an Employee experiencing family violence under subclause 66.6).</p><p><strong>(a)</strong> Access to Employees – Electronic communication The Employer will ensure that:</p><p><strong>(i)</strong> emails from the Union domain name are not blocked or restricted by or on behalf of the Employer, except in respect of any individual Employee who has made a written request to the Employer to block such emails;</p><p><strong>(ii)</strong> emails from Employees to the Union are not blocked or restricted by or on behalf of the Employer;</p><p><strong>(iii)</strong> access from Employer computers and like devices to Union websites and online information is not blocked, or limited; and</p><p><strong>(iv)</strong> where a genuine security concern arises regarding the above, the Employer will immediately notify the Union to enable the security concern to be addressed.</p><p><strong>(b)</strong> Access to Employees – Orientation</p><p><strong>(i)</strong> The Union may attend and address new Employees as part of orientation/induction programs for new Employees, provided that any attendance for the purposes of discussions with the Employees meets the right of entry requirements under Part 3-4 of the Act (Entry Requirements). The details of such attendance will be arranged by the Employer in consultation with the Union.</p><p><strong>(ii)</strong> An Employer will advise the Union of the date, time and location of orientation/induction programs not less than 14 days prior to the orientation/induction program.</p><p><strong>(iii)</strong> Those covered by this Agreement acknowledge the increasing role that technology plays in orientation/induction. An Employer and Union may agree to an alternative means by which the Union can access new Employees including where orientation/induction programs are conducted on-line or the Union cannot reasonably attend, provided that such access is consistent with the Entry Requirements.</p><p><strong>(c)</strong> Delegates and HSRs NOTE: Additional rights of HSRs are contained in the OHS Act.</p><p><strong>(i)</strong> In this subclause 83.1(c) Representative means a Union Delegate, or HSR.</p><p><strong>(ii)</strong> A Representative is entitled to reasonable time release from duty to: A. attend to matters relating to industrial, occupational health and safety or other relevant matters such as assisting with grievance procedures and attending committee meetings; B. access reasonable preparation time before meetings with management disciplinary or grievance meetings with a Union member; C. appear as a witness or participate in conciliation or arbitration, before the Commission; D. present information on the Union at orientation sessions for new Employees.</p><p><strong>(iii)</strong> A Representative required to attend management or consultative meetings outside of paid time will be paid to attend.</p><p><strong>(iv)</strong> A Representative will be provided with access to facilities such as telephones, computers, email, noticeboards and meeting rooms in a manner that does not adversely affect service delivery and work requirements of the Employer. In the case of an HSR, facilities will include other facilities as necessary to enable them to perform their functions as prescribed under the OHS Act.</p><p><strong>(d)</strong> Noticeboard A noticeboard for the Union’s use will be readily accessible in each ward/unit/work area or nearest staff room where persons eligible to be members of the Union are employed.</p><p><strong>(e)</strong> Meeting Space In the absence of agreement on a location for the holding of Union meetings, the room where one (1) or more of the Employees who may participate in the meeting ordinarily take meal or other breaks will be the meeting room for the purpose of Union meetings. Nothing in this clause 83 is intended to override the operation of the Act.</p><p><strong>(f)</strong> Secondment to the Union The Employer will, on application, grant leave without pay to an Employee for the purpose of secondment or other arrangement to work for the Union subject to the Employer’s reasonable operational requirements.</p><p><strong>(g)</strong> Employees holding Union official positions The Employer will, on application by the Union, grant leave without loss of pay to an Employee for the purpose of fulfilling their duties as an official of the Branch</p><p>Committee (which includes the Governance and Finance Committee), National Executive or National Council of the Union. For a member of the Branch Committee, this currently involves 12 half day meetings per year (plus travel time). For National Council members this currently involves an additional two (2) day meeting (plus travel time).</p><p><strong>(h)</strong> Union Training NOTE: an HSR may be entitled to any training in accordance with the OHS Act rather than, or in addition to, this clause 83.</p><p><strong>(i)</strong> Subject to the conditions in this subclause 83.1(h), Employees selected by the Union to attend training courses on industrial relations and/or health and safety will be entitled to a maximum of five (5) days’ paid leave per calendar year per Employee.</p><p><strong>(ii)</strong> Leave in excess of five (5) days and up to ten days may be granted in a calendar year subject to the total leave being granted in that year and in the subsequent year not exceeding ten (10) days.</p><p><strong>(iii)</strong> The granting of leave will be subject to the Employer’s operational requirements. The granting of leave will not be unreasonably withheld.</p><p><strong>(iv)</strong> The Employer will notify the Employee in writing whether leave will be granted within seven (7) days of the application being made. If the leave is not approved, the reasons will be included in the written notification to the Employee.</p><p><strong>(v)</strong> Leave under this subclause 83.1(h) is granted on the following conditions: A. applications are accompanied by a statement from the Union advising that it has nominated the Employee or supports the application; B. the training is conducted by the Union, an association of unions or accredited training provider; and C. the application is made as early as practicable and not less than two (2) weeks before the training.</p><p><strong>(vi)</strong> Once union training leave has been granted by the Employer it will only be revoked by mutual agreement which may be at the request of the Employee, save that the Employer will not unreasonably refuse a request by an Employee to revoke the granting of leave.</p><p><strong>(vii)</strong> The Employee will be paid their ordinary pay (for normal rostered hours, but excluding shift work, overtime and other allowances.</p><p><strong>(viii)</strong> Leave in accordance with this clause 83 may include necessary travelling time in normal hours immediately before or after the course.</p><p><strong>(ix)</strong> Leave granted under this clause 83 will count as service for all purposes of this Agreement.</p><p><strong>(x)</strong> Expenses associated with attendance at training courses, including fares, accommodation and meal costs are not the responsibility of the Employer.</p><p><strong>83.2</strong> Workplace Implementation Committees (WIC)</p><p><strong>(a)</strong> A local Workplace Implementation Committee (WIC) will continue or, if there is not currently a WIC in operation, be established at each Employer. Having regard for the size and location, a WIC may be appropriate at each facility/campus. The WIC will, where practicable, comprise equal numbers of representatives of the Employer and the Union for the purposes of discussing:</p><p><strong>(i)</strong> Agreement implementation;</p><p><strong>(ii)</strong> on-going monitoring and assessment of the implementation of this Agreement; and</p><p><strong>(iii)</strong> to deal with any local disputes that may arise, without limiting the Dispute Resolution Procedure in this Agreement.</p><p><strong>(b)</strong> Priority Items for consideration by the WIC will include:</p><p><strong>(i)</strong> implementation and operation of the Lead Apron Allowance - <a href="/eba/ebas/allied-health/allowances/44A-lead-apron-allowance.html">clause 44A</a>;</p><p><strong>(ii)</strong> progress of implementing payments under this Agreement;</p><p><strong>(iii)</strong> implementation and operation of Workload Allocation and Safe Staffing – <a href="/eba/ebas/allied-health/classification-staffing/90-workload-allocation-and-safe-staffing.html">clause 90</a>;</p><p><strong>(iv)</strong> implementation and operation of Backfill – <a href="/eba/ebas/allied-health/classification-staffing/91-backfill.html">clause 91</a>;</p><p><strong>(v)</strong> Translation arrangements following the abolition of AHP1 Grade 1 Years 1 and 7 pay points – <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>;</p><p><strong>(vi)</strong> AHP1 Grade 1 to Grade 2 progression – <a href="/eba/ebas/allied-health/appendices/4-classification-definitions.html">Appendix 4</a>.</p><p><strong>(c)</strong> Translations</p><p><strong>(i)</strong> Where the Agreement is being implemented at: A. Boort District Health; B. Cohuna District Hospital; C. Dhelkaya Health (at Maldon Hospital); D. Casterton Memorial Hospital; E. The Queen Elizabeth Centre; and F. Tweddle Child &amp; Family Health.</p><p><strong>(ii)</strong> the translation of the Employer’s existing classification structures for Employees covered by this Agreement to the classification structures in this Agreement. These translations are to have the same affect, as far as is possible, as the translations in <a href="/eba/ebas/allied-health/appendices/2-wage-rates.html">Appendix 2</a>, Part C of the 2016 Agreement.</p><p><strong>(d)</strong> In relation to the Employers referred to at subclause 83.2(c)(i) at the request of the Union or the Employer, a WIC meeting or meetings will occur. The meeting(s)</p><p>will occur at a mutually agreeable time, save that a request to meet at a specific time will not be unreasonably refused.</p><p>Plain language terms: union rep, delegate.</p>',50)])])}const g=t(i,[["render",r]]);export{d as __pageData,g as default};
